parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const kbId = body.kbId;
const sourceUrl = body.sourceUrl;
const sourceBranch = body.sourceBranch || 'main';
const sourcePath = (body.sourcePath || '').replace(/^\/+|\/+$/g, '');
const difyDatasetId = body.difyDatasetId;
const difyApiUrl = body.difyApiUrl || 'http://dify-api:5001';
const difyApiKey = body.difyApiKey || '';
const syncJobId = body.syncJobId;
const progressCallbackUrl = body.progressCallbackUrl;
const progressCallbackToken = body.progressCallbackToken || '';
const sourceToken = body.sourceToken || '';

if (!kbId || !sourceUrl || !difyDatasetId || !difyApiKey || !syncJobId) {
  throw new Error('Missing required sync parameters: kbId, sourceUrl, difyDatasetId, difyApiKey, syncJobId');
}

const match = sourceUrl.match(/gitlab\.com\/([^/]+(?:\/[^/]+)*)\/([^/]+)$/);
if (!match) throw new Error('Invalid GitLab URL: ' + sourceUrl);
const namespace = match[1];
const repo = match[2].replace(/\.git$/, '');
const projectPath = `${namespace}/${repo}`;
const encodedProjectPath = encodeURIComponent(projectPath);

return [{ json: { kbId, projectPath, encodedProjectPath, branch: sourceBranch, path: sourcePath, difyDatasetId, difyApiUrl, difyApiKey, syncJobId, progressCallbackUrl, progressCallbackToken, sourceToken } }];

const tree = $input.first().json || [];
const params = $('Parse Sync Params').first().json;
const basePath = params.path || '';

const files = tree
  .filter(item => {
    if (item.type !== 'blob') return false;
    const ext = item.path.split('.').pop().toLowerCase();
    if (!['md', 'txt', 'rst', 'mdx'].includes(ext)) return false;
    if (basePath && !item.path.startsWith(basePath)) return false;
    return true;
  })
  .slice(0, 500);

return files.map(file => ({
  json: {
    ...params,
    filePath: file.path,
    totalFiles: files.length,
    encodedFilePath: encodeURIComponent(file.path)
  }
}));

